def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re

    # Helper: Find the objective text shape
    def find_objective_text_shape(slide):
        for shape in slide.shapes:
            if not shape.has_text_frame:
                continue
            text = shape.text_frame.text.strip().lower()
            if 'objective' in text or re.search(r'(objective[s]?[:]?|goal[s]?[:]?|learning outcome[s]?[:]?|purpose[:]?|aim[s]?[:]?|target[s]?[:]?|intended outcome[s]?[:]?|what you will learn)', text):
                return shape
        return None

    prs = Presentation(modified_ppt_path)
    slide = prs.slides[10] if len(prs.slides) > 10 else None
    if not slide:
        return ("Slide 11 not found.", 0.0)

    shape = find_objective_text_shape(slide)
    if shape is None:
        return ("Objective text not found on slide 11.", 0.0)

    # Check if all text is italic
    tf = shape.text_frame
    all_italic = True
    for paragraph in tf.paragraphs:
        for run in paragraph.runs:
            if not run.font.italic:
                all_italic = False
                break
        if not all_italic:
            break
    if all_italic:
        return ("All objective text on slide 11 is italicized.", 1.0)
    else:
        # New rule: If only the first word "Objective" is italicized, still give full credit.
        # Find first non-empty paragraph
        first_para = None
        for p in tf.paragraphs:
            if p.text and p.text.strip():
                first_para = p
                break
        if first_para:
            para_text = first_para.text.lstrip()
            target = "objective"
            if para_text.lower().startswith(target):
                # Ensure word boundary after 'Objective' (space, colon, punctuation, or end)
                boundary_ok = len(para_text) == len(target) or (len(para_text) > len(target) and not para_text[len(target)].isalnum())
                if boundary_ok:
                    # Check italic for the characters forming 'Objective'
                    needed_len = len(target)
                    collected = 0
                    italic_flags = []
                    for run in first_para.runs:
                        if collected >= needed_len:
                            break
                        run_text = run.text
                        for ch in run_text:
                            if collected >= needed_len:
                                break
                            # skip leading whitespace before starting word
                            if collected == 0 and ch.isspace():
                                continue
                            italic_flags.append(bool(run.font.italic))
                            collected += 1
                    if collected == needed_len and italic_flags and all(italic_flags):
                        return ("First word 'Objective' is italicized (accepted criteria).", 1.0)
        return ("Not all objective text is italicized.", 0.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re

    # Helper: Find the objective text shape
    def find_objective_text_shape(slide):
        for shape in slide.shapes:
            if not shape.has_text_frame:
                continue
            text = shape.text_frame.text.strip().lower()
            if 'objective' in text or re.search(r'(objective[s]?[:]?|goal[s]?[:]?|learning outcome[s]?[:]?|purpose[:]?|aim[s]?[:]?|target[s]?[:]?|intended outcome[s]?[:]?|what you will learn)', text):
                return shape
        return None

    prs_mod = Presentation(modified_ppt_path)
    prs_orig = Presentation(original_ppt_path)
    slide_mod = slide_orig = None
    for s in prs_mod.slides:
        if hasattr(s, 'slide_id') and s.slide_id == '11':
            slide_mod = s
            break
    if not slide_mod:
        # fallback: use slide number (1-based)
        if len(prs_mod.slides) >= 11:
            slide_mod = prs_mod.slides[10]
    for s in prs_orig.slides:
        if hasattr(s, 'slide_id') and s.slide_id == '11':
            slide_orig = s
            break
    if not slide_orig:
        if len(prs_orig.slides) >= 11:
            slide_orig = prs_orig.slides[10]
    if not slide_mod or not slide_orig:
        return ("Slide 11 not found in one of the presentations.", 0.0)

    shape_obj = find_objective_text_shape(slide_mod)
    # Gather text from all shapes except objective
    non_obj_shapes_mod = [sh for sh in slide_mod.shapes if sh != shape_obj and hasattr(sh, 'text_frame') and sh.has_text_frame]
    non_obj_shapes_orig = [sh for sh in slide_orig.shapes if hasattr(sh, 'text_frame') and sh.has_text_frame]

    # For each non-objective shape, check if any run was made italic in mod but was not in orig
    score = 1.0
    for mod_sh, orig_sh in zip(non_obj_shapes_mod, non_obj_shapes_orig):
        tf_mod = mod_sh.text_frame
        tf_orig = orig_sh.text_frame
        for p_mod, p_orig in zip(tf_mod.paragraphs, tf_orig.paragraphs):
            # Compare runs by index
            for run_mod, run_orig in zip(p_mod.runs, p_orig.runs):
                if not run_orig.font.italic and run_mod.font.italic:
                    return ("Detected unintended italics on non-objective text on slide 11.", 0.0)
    return ("No unintended italicization on slide 11.", 1.0)

